import { _decorator, Component, director, Node, Label, Button, Vec3, tween, UIOpacity } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('GuideManager')
export class GuideManager extends Component {
    static instance: GuideManager = null;
    
    @property(Node)
    guideMask: Node = null;
    
    @property(Node)
    guideHand: Node = null;
    
    @property(Label)
    guideText: Label = null;
    
    @property(Button)
    nextBtn: Button = null;
    
    private currentStep: number = 0;
    private guideSteps = [
        { text: '欢迎来到财神大陆！我是你的引导助手。', target: null },
        { text: '点击"供奉"进入庙宇，向财神供奉可以获得香火钱和功德。', target: 'worshipBtn' },
        { text: '点击"化缘"可以去各地化缘，获得更多香火钱，但要注意风险！', target: 'almsBtn' },
        { text: '积累足够的功德后，点击"升级"可以进化你的神像。', target: 'upgradeBtn' },
        { text: '点击"背包"可以查看你的物品和装备。', target: 'bagBtn' },
        { text: '香火钱会自然增长，法力也会慢慢恢复。', target: null },
        { text: '现在就开始你的财神之旅吧！', target: null }
    ];
    
    onLoad() {
        if (GuideManager.instance === null) {
            GuideManager.instance = this;
        }
        
        this.nextBtn.node.on(Button.EventType.CLICK, this.onNextStep, this);
    }
    
    startGuide() {
        this.currentStep = 0;
        this.showStep();
        this.guideMask.active = true;
    }
    
    showStep() {
        const step = this.guideSteps[this.currentStep];
        this.guideText.string = step.text;
        
        if (step.target) {
            // 高亮目标按钮
            this.guideHand.active = true;
            // 移动手指到目标位置
        } else {
            this.guideHand.active = false;
        }
    }
    
    onNextStep() {
        this.currentStep++;
        
        if (this.currentStep >= this.guideSteps.length) {
            this.endGuide();
        } else {
            this.showStep();
        }
    }
    
    endGuide() {
        this.guideMask.active = false;
        // 标记已完成新手引导
        GameManager.getInstance().playerData.save();
    }
    
    static getInstance(): GuideManager {
        return GuideManager.instance;
    }
}
